-- -----------------------------------------------------------------------------
-- 4. SYMPTOM FORMS (for all COMPLETED appointments)
-- -----------------------------------------------------------------------------
INSERT INTO symptom_forms (id, appointment_id, symptoms_text, duration_days, severity, medications, known_conditions, ai_brief, created_at) VALUES

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000001',
                                                                                                                                                 'Chest tightness and shortness of breath when climbing stairs or walking briskly. No pain at rest but I feel my heart racing occasionally.',
                                                                                                                                                 14, 7, 'Amlodipine 5mg daily', 'Hypertension diagnosed 3 years ago',
                                                                                                                                                 'Summary: Patient reports exertional chest tightness and dyspnoea on moderate activity for 14 days, with intermittent palpitations at rest. Severity 7/10. Known hypertensive on amlodipine.

                                                                                                                                                Urgency: High — Exertional chest symptoms in a hypertensive patient require prompt cardiac evaluation to exclude ACS, heart failure, or significant coronary artery disease.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any radiation of discomfort to the arm, jaw, or back?
                                                                                                                                                - Any ankle swelling or orthopnoea?
                                                                                                                                                - How well controlled has BP been recently?

                                                                                                                                                Background: Current amlodipine dose may be insufficient. Consider ECG, BNP, and stress testing.',
                                                                                                                                                 NOW() - INTERVAL '60 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000002',
                                                                                                                                                 'Feeling very low in mood for the past few weeks, difficulty sleeping, low energy and losing interest in things I used to enjoy. Some days I don''t want to get out of bed.',
                                                                                                                                                 21, 6, 'None', 'No known conditions',
                                                                                                                                                 'Summary: Patient describes a 3-week history of low mood, anhedonia, insomnia, and fatigue consistent with a depressive episode. Severity 6/10. No current medications or known psychiatric history.

                                                                                                                                                Urgency: Medium — Duration and symptom cluster suggest moderate depression warranting formal assessment and likely treatment initiation.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any thoughts of self-harm or hopelessness?
                                                                                                                                                - Any identifiable trigger or recent life stressor?
                                                                                                                                                - Appetite changes or weight loss?

                                                                                                                                                Background: First presentation — full PHQ-9 assessment recommended. Explore psychotherapy and pharmacotherapy options.',
                                                                                                                                                 NOW() - INTERVAL '55 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000003',
                                                                                                                                                 'Severe headaches almost every day, throbbing pain mostly on one side, sometimes with nausea. Light and noise make it worse. I have missed work several times.',
                                                                                                                                                 30, 8, 'Ibuprofen (overusing, almost daily)', 'Migraines since teenage years',
                                                                                                                                                 'Summary: Patient with known migraine history presents with daily or near-daily headaches for one month, rated 8/10. Unilateral throbbing with photophobia, phonophobia, and nausea. Likely medication overuse headache given daily NSAID use.

                                                                                                                                                Urgency: Medium-High — Medication overuse headache must be addressed; preventive migraine therapy strongly indicated.

                                                                                                                                                Suggested questions:
                                                                                                                                                - How many days per month are you taking ibuprofen?
                                                                                                                                                - Any aura (visual disturbance, tingling before headache)?
                                                                                                                                                - Sleep and stress levels currently?

                                                                                                                                                Background: Discuss NSAID withdrawal plan and initiate preventive therapy (topiramate, propranolol, or CGRP antagonist).',
                                                                                                                                                 NOW() - INTERVAL '50 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000004',
                                                                                                                                                 'Heavy and painful periods for the last 6 months, getting worse each cycle. Pelvic pain between periods too. Bloating and pain during intercourse.',
                                                                                                                                                 180, 7, 'Mefenamic acid during periods', 'None',
                                                                                                                                                 'Summary: Patient presents with a 6-month history of progressively worsening dysmenorrhoea, intermenstrual pelvic pain, dyspareunia, and bloating. Severity 7/10. Symptom cluster is highly suggestive of endometriosis.

                                                                                                                                                Urgency: Medium — Symptoms significantly impact quality of life. Early diagnosis and management can prevent disease progression.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any change in bowel or bladder habits around periods?
                                                                                                                                                - Family history of endometriosis?
                                                                                                                                                - Any previous pelvic ultrasound or investigations?

                                                                                                                                                Background: Pelvic ultrasound recommended; consider laparoscopy for definitive diagnosis if imaging inconclusive.',
                                                                                                                                                 NOW() - INTERVAL '48 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000005',
                                                                                                                                                 'Right knee pain and swelling after a football injury last week. I heard a pop when it happened. Difficult to fully straighten the knee and it feels unstable.',
                                                                                                                                                 7, 8, 'Naproxen 500mg twice daily', 'None',
                                                                                                                                                 'Summary: Acute right knee injury with audible pop, subsequent swelling, extension deficit, and instability. Severity 8/10. Mechanism and signs are highly suggestive of ACL tear.

                                                                                                                                                Urgency: High — Suspected ACL rupture requires urgent orthopaedic evaluation and MRI to confirm diagnosis and plan management.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Was there immediate swelling (within 2 hours) or delayed swelling?
                                                                                                                                                - Can you bear full weight on the leg?
                                                                                                                                                - Any previous knee injuries?

                                                                                                                                                Background: Lachman test and anterior drawer test findings will guide urgency of surgical referral.',
                                                                                                                                                 NOW() - INTERVAL '45 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000006',
                                                                                                                                                 'Red, itchy rash spreading on both arms and neck. Very dry and flaky skin. Gets worse in winter and when I''m stressed. Had this on and off since childhood.',
                                                                                                                                                 365, 5, 'OTC hydrocortisone cream occasionally', 'Atopic eczema (childhood)',
                                                                                                                                                 'Summary: Patient with childhood atopic eczema presents with a flare of pruritic, erythematous, dry, and scaly rash on bilateral arms and neck. Severity 5/10. Seasonal and stress-related exacerbations noted.

                                                                                                                                                Urgency: Low — Chronic condition requiring optimisation of maintenance therapy rather than emergency management.

                                                                                                                                                Suggested questions:
                                                                                                                                                - What moisturiser are you currently using and how often?
                                                                                                                                                - Any new soaps, detergents, or skincare products recently?
                                                                                                                                                - Any recent infections or illnesses before the flare?

                                                                                                                                                Background: Step up topical therapy; consider dupilumab if moderate-severe and inadequately controlled.',
                                                                                                                                                 NOW() - INTERVAL '40 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000007',
                                                                                                                                                 'Chest pain and feeling of heart fluttering. The episodes come and go, lasting a few seconds to a few minutes. I feel dizzy afterwards. One episode happened at rest.',
                                                                                                                                                 45, 7, 'None', 'None known',
                                                                                                                                                 'Summary: Patient describes recurrent paroxysmal palpitations with associated chest discomfort and post-episode dizziness for 45 days. One episode at rest. Severity 7/10. No prior cardiac history or medications.

                                                                                                                                                Urgency: High — Palpitations with dizziness and chest discomfort require urgent cardiac evaluation to exclude significant arrhythmia.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Are episodes regular or irregular in rhythm?
                                                                                                                                                - Any family history of sudden cardiac death or arrhythmia?
                                                                                                                                                - Any triggers identified (caffeine, exercise, stress)?

                                                                                                                                                Background: 12-lead ECG urgent; consider 24-hour Holter monitor or event recorder to capture episodes.',
                                                                                                                                                 NOW() - INTERVAL '38 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000008',
                                                                                                                                                 'Patches of thick, scaly skin on my elbows, knees and scalp. Very itchy and sometimes bleeds when I scratch. Has been getting worse over the last 3 months.',
                                                                                                                                                 90, 6, 'Coal tar shampoo for scalp', 'Plaque psoriasis',
                                                                                                                                                 'Summary: Patient with known plaque psoriasis presents with 3-month worsening affecting elbows, knees, and scalp. Severity 6/10. Current therapy limited to OTC coal tar.

                                                                                                                                                Urgency: Low-Medium — Disease appears to be stepping up; formal PASI scoring and consideration of systemic or biologic therapy warranted.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any joint pain or swelling (psoriatic arthritis screening)?
                                                                                                                                                - Any recent infections, medications, or stress coinciding with worsening?
                                                                                                                                                - Previous treatments tried and discontinued?

                                                                                                                                                Background: Assess DLQI to quantify impact; if moderate-severe, discuss methotrexate, biologics, or PDE4 inhibitors.',
                                                                                                                                                 NOW() - INTERVAL '35 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000009',
                                                                                                                                                 'Heart palpitations, extreme tiredness, feeling cold all the time, and putting on weight despite not changing my diet. Hair has been falling out more than usual.',
                                                                                                                                                 60, 5, 'None', 'None',
                                                                                                                                                 'Summary: Patient presents with a classic symptom cluster of fatigue, cold intolerance, weight gain, hair loss, and palpitations over 2 months. Severity 5/10. High suspicion for hypothyroidism.

                                                                                                                                                Urgency: Medium — Likely thyroid dysfunction; simple blood tests will confirm and guide treatment.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any neck swelling or difficulty swallowing?
                                                                                                                                                - Family history of thyroid disease?
                                                                                                                                                - Any recent pregnancy or significant life stress?

                                                                                                                                                Background: TSH, free T4, and thyroid antibodies (TPO) will be diagnostic. If confirmed hypothyroid, levothyroxine initiation indicated.',
                                                                                                                                                 NOW() - INTERVAL '30 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000010',
                                                                                                                                                 'Feeling anxious all the time, even about small things. Heart racing, sweating, difficulty concentrating at work. I have started avoiding social situations.',
                                                                                                                                                 90, 7, 'None', 'No known conditions',
                                                                                                                                                 'Summary: Patient reports 3 months of generalised anxiety with somatic symptoms (palpitations, diaphoresis), cognitive impairment, and behavioural avoidance. Severity 7/10. Significant occupational and social impact.

                                                                                                                                                Urgency: Medium — Generalised anxiety disorder with functional impairment warrants structured treatment.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any panic attacks with sudden intense fear?
                                                                                                                                                - Any low mood or depressive symptoms alongside anxiety?
                                                                                                                                                - Any alcohol or substance use to manage symptoms?

                                                                                                                                                Background: GAD-7 assessment recommended. First-line: SSRI plus CBT referral. Discuss psychoeducation and safety net.',
                                                                                                                                                 NOW() - INTERVAL '28 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000011',
                                                                                                                                                 'Stomach pain after eating, bloating, and sometimes diarrhoea. Worse with certain foods especially dairy and wheat. I have lost about 4kg in the last 2 months.',
                                                                                                                                                 60, 6, 'Omeprazole 20mg', 'None',
                                                                                                                                                 'Summary: Patient presents with 2-month history of postprandial abdominal pain, bloating, and diarrhoea with dietary triggers and unintentional 4kg weight loss. Severity 6/10.

                                                                                                                                                Urgency: Medium-High — Unintentional weight loss with GI symptoms requires investigation to exclude coeliac disease, IBD, or other organic pathology.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any blood in stool or rectal bleeding?
                                                                                                                                                - Any mouth ulcers or skin rashes?
                                                                                                                                                - Family history of IBD or coeliac disease?

                                                                                                                                                Background: Bloods including coeliac screen, CRP, FBC, and LFTs. Consider colonoscopy referral given weight loss.',
                                                                                                                                                 NOW() - INTERVAL '25 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000012',
                                                                                                                                                 'My 4-year-old has had recurring ear infections, 5 times in the last year. Each time treated with antibiotics but keeps coming back. Affects sleep and is irritable.',
                                                                                                                                                 365, 5, 'Amoxicillin courses (recurrent)', 'Recurrent acute otitis media',
                                                                                                                                                 'Summary: Child aged 4 with 5 episodes of acute otitis media in 12 months, each requiring antibiotics. Currently symptomatic with irritability and sleep disturbance. Severity 5/10.

                                                                                                                                                Urgency: Medium — Recurrent AOM threshold met for ENT referral and consideration of grommets.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any hearing concerns between episodes?
                                                                                                                                                - Any speech or language delay?
                                                                                                                                                - Attends nursery or daycare (increases exposure risk)?

                                                                                                                                                Background: Refer to ENT for assessment; grommet insertion likely indicated. Audiology assessment warranted.',
                                                                                                                                                 NOW() - INTERVAL '22 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000013',
                                                                                                                                                 'Lower back pain radiating down the left leg to the foot. Numbness and tingling in the toes. Sitting makes it much worse. Started after lifting heavy boxes.',
                                                                                                                                                 21, 8, 'Diclofenac 50mg three times daily', 'None',
                                                                                                                                                 'Summary: Patient presents with 3-week history of acute low back pain with left L4-S1 radiculopathy following heavy lifting. Severity 8/10. Neurological symptoms (numbness, tingling to foot) present.

                                                                                                                                                Urgency: Medium-High — Radiculopathy with neurological symptoms requires assessment to exclude significant disc herniation with nerve compression.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any weakness in the foot or difficulty walking on tiptoes/heels?
                                                                                                                                                - Any bladder or bowel changes (red flag for cauda equina)?
                                                                                                                                                - Previous back problems or imaging?

                                                                                                                                                Background: Urgent MRI lumbar spine if any red flags. Physiotherapy referral; consider nerve root injection if persistent.',
                                                                                                                                                 NOW() - INTERVAL '20 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000014',
                                                                                                                                                 'Struggling with intrusive thoughts and memories related to a traumatic event from 2 years ago. Nightmares, feeling on edge, avoiding certain places that remind me.',
                                                                                                                                                 730, 8, 'None', 'No formal diagnosis',
                                                                                                                                                 'Summary: Patient presents with a 2-year history of intrusive memories, nightmares, hypervigilance, and avoidance behaviours following a traumatic event. Severity 8/10. Symptom profile consistent with PTSD.

                                                                                                                                                Urgency: Medium — Established PTSD with significant impact on daily functioning; evidence-based trauma therapy should be initiated.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any self-harm or suicidal ideation?
                                                                                                                                                - Any substance use as a coping mechanism?
                                                                                                                                                - Has any previous therapy been attempted?

                                                                                                                                                Background: Trauma-focused CBT or EMDR are first-line. Pharmacotherapy (SSRI) may help concurrent symptoms. Safety planning essential.',
                                                                                                                                                 NOW() - INTERVAL '18 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000015',
                                                                                                                                                 'Forgetting where I put things, missing appointments, struggling to remember names. My family have noticed I repeat myself. This has been slowly getting worse over 2 years.',
                                                                                                                                                 730, 5, 'Metformin 500mg, Ramipril 5mg', 'Type 2 diabetes, hypertension',
                                                                                                                                                 'Summary: Patient and family report 2-year progressive memory decline including episodic memory loss, word-finding difficulty, and repetition. Severity 5/10. Known T2DM and hypertension — vascular risk factors present.

                                                                                                                                                Urgency: Medium — Progressive cognitive decline requires formal neuropsychological assessment and diagnostic workup.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any changes in personality or behaviour?
                                                                                                                                                - Able to manage finances, medications, and daily tasks independently?
                                                                                                                                                - Any family history of dementia?

                                                                                                                                                Background: MMSE/MoCA, bloods (B12, folate, TFTs, FBC), and brain MRI. Refer to memory clinic. Optimise vascular risk factors.',
                                                                                                                                                 NOW() - INTERVAL '15 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000016',
                                                                                                                                                 'Irregular heartbeat, sometimes feeling it skip and then thump. Episodes last from minutes to hours. I feel breathless and lightheaded when they happen.',
                                                                                                                                                 90, 7, 'Bisoprolol 2.5mg', 'Hypertension',
                                                                                                                                                 'Summary: Patient on bisoprolol for hypertension presents with 3-month history of paroxysmal palpitations with associated dyspnoea and presyncope. Episodes variable in duration. Severity 7/10.

                                                                                                                                                Urgency: High — Paroxysmal symptoms with presyncope in a medicated hypertensive suggest paroxysmal AF or other significant arrhythmia.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Are you monitoring your BP at home? What are recent readings?
                                                                                                                                                - Any episodes of actual syncope (loss of consciousness)?
                                                                                                                                                - Any thyroid history?

                                                                                                                                                Background: 12-lead ECG, TFTs, echo; ambulatory monitoring (7-day patch) to capture paroxysmal events.',
                                                                                                                                                 NOW() - INTERVAL '14 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000017',
                                                                                                                                                 'Visual disturbances before headaches, flashing lights and zigzag lines lasting about 20 minutes. Then a severe headache follows. Has happened 4 times this month.',
                                                                                                                                                 30, 7, 'Sumatriptan 50mg (recently prescribed)', 'Migraine with aura (new diagnosis)',
                                                                                                                                                 'Summary: Patient with recently diagnosed migraine with aura presenting with 4 attacks in one month. Classic aura — scintillating scotoma lasting ~20 minutes preceding severe headache. Severity 7/10.

                                                                                                                                                Urgency: Medium — Increasing attack frequency warrants preventive therapy initiation.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Is sumatriptan effective and how quickly does it work?
                                                                                                                                                - Any combined oral contraceptive use (contraindicated in aura)?
                                                                                                                                                - Any cardiovascular risk factors?

                                                                                                                                                Background: Monthly attack frequency meets criteria for preventive therapy. Combined OCP is contraindicated with aura — discuss contraception. First-line preventives: topiramate, amitriptyline, propranolol.',
                                                                                                                                                 NOW() - INTERVAL '12 days'),

                                                                                                                                                (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000018',
                                                                                                                                                 'Excessive thirst and frequent urination, especially at night. Feeling very tired and blurred vision on some days. Weight loss of 5kg over the last month without trying.',
                                                                                                                                                 30, 7, 'None', 'None',
                                                                                                                                                 'Summary: Patient presents with classic triad of polydipsia, polyuria, and weight loss with fatigue and intermittent blurred vision over 30 days. Undiagnosed. Severity 7/10. High suspicion for new onset diabetes mellitus.

                                                                                                                                                Urgency: High — Symptom triad with unintentional weight loss is highly suggestive of type 1 or type 2 DM. HbA1c and fasting glucose urgent.

                                                                                                                                                Suggested questions:
                                                                                                                                                - Any nausea, vomiting, or abdominal pain (DKA screening)?
                                                                                                                                                - Any family history of diabetes?
                                                                                                                                                - Age and BMI context for T1 vs T2 likelihood?

                                                                                                                                                Background: Urgent blood glucose and HbA1c. If DKA symptoms present, refer to ED immediately. If T2DM, initiate lifestyle and metformin.',
                                                                                                                                                 NOW() - INTERVAL '10 days');

-- -----------------------------------------------------------------------------
-- 5. APPOINTMENT NOTES (doctor notes for all COMPLETED appointments)
-- doctor_id references users.id of the treating doctor's user account
-- -----------------------------------------------------------------------------
INSERT INTO appointment_notes (id, appointment_id, doctor_id, notes_text, created_at) VALUES

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001',
                                                                                           'Patient presented with exertional chest tightness and dyspnoea for 2 weeks. BP today 148/92 — poorly controlled on current amlodipine dose. Resting ECG showed no acute changes. BNP ordered. Increased amlodipine to 10mg daily and added perindopril 4mg. Referred for stress echocardiogram. Advised to avoid strenuous activity until results available. Follow up in 2 weeks.',
                                                                                           NOW() - INTERVAL '60 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000005',
                                                                                           'Patient presenting with 3-week depressive episode — first presentation. PHQ-9 score 16 (moderate-severe). No suicidal ideation. Agreed to trial sertraline 50mg, to increase to 100mg at 4 weeks if tolerated. CBT referral submitted. Discussed sleep hygiene and gentle exercise. Safety net provided — advised to contact if symptoms worsen. Review in 4 weeks.',
                                                                                           NOW() - INTERVAL '55 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000003', 'a1000000-0000-0000-0000-000000000002',
                                                                                           'Chronic migraine with suspected medication overuse headache — ibuprofen taken 22 out of last 30 days. Discussed medication overuse cycle clearly. Agreed on gradual ibuprofen withdrawal plan over 4 weeks. Initiated topiramate 25mg titrating to 50mg for prevention. Prescribed nasal sumatriptan as acute rescue limited to max 10 days/month. Referred to headache clinic. Migraine diary requested.',
                                                                                           NOW() - INTERVAL '50 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000007',
                                                                                           'Presentation strongly suggestive of endometriosis — progressive dysmenorrhoea, deep dyspareunia, intermenstrual pelvic pain for 6 months. Pelvic exam performed — posterior fornix tenderness. Transvaginal ultrasound ordered. Started on combined OCP continuously to manage symptoms while awaiting imaging. Referred to endometriosis specialist for laparoscopic assessment. Discussed disease course and management options including laparoscopic excision.',
                                                                                           NOW() - INTERVAL '48 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000006',
                                                                                           'Acute right knee injury with history of pivot and audible pop, immediate swelling — high suspicion ACL tear. Lachman positive, anterior drawer positive. Full weight bearing possible but painful. MRI right knee ordered urgently. RICE advised, crutches provided. Naproxen continued. Referred to sports medicine physiotherapist for assessment while awaiting MRI. Surgical consultation likely needed — patient counselled on ACL reconstruction process and expected recovery timeline.',
                                                                                           NOW() - INTERVAL '45 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000006', 'a1000000-0000-0000-0000-000000000003',
                                                                                           'Moderate atopic eczema flare — bilateral antecubital fossa, forearms, and neck. EASI score 18 (moderate). Identified new washing detergent as likely trigger — advised change to fragrance-free alternative. Prescribed betamethasone valerate 0.1% for 2-week course on affected areas. Reinforced daily emollient use — prescribed Epaderm 500g. Discussed wet wrapping technique for flares. Review in 6 weeks; will consider dupilumab referral if inadequate response.',
                                                                                           NOW() - INTERVAL '40 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000007', 'a1000000-0000-0000-0000-000000000011',
                                                                                           'Palpitations and chest discomfort — 12-lead ECG today showed no acute arrhythmia but baseline right bundle branch block noted. 48-hour Holter monitor fitted. Echo ordered to assess structure and function. Holter results pending. Advised to avoid caffeine and keep symptom diary noting time, duration, and associated symptoms. Patient reassured about low immediate risk but importance of investigation explained. Follow up with Holter results in 5 days.',
                                                                                           NOW() - INTERVAL '38 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000008', 'a1000000-0000-0000-0000-000000000009',
                                                                                           'Plaque psoriasis flare — PASI 14 (moderate), DLQI 16 (very large effect on quality of life). Elbows, knees, and scalp affected. Psoriatic arthritis screening negative — no joint swelling or morning stiffness. Prescribed calcipotriol/betamethasone dipropionate gel for scalp and body plaques. Discussed eligibility for biologic therapy given DLQI score. Referred to dermatology nurse specialist for education and support. PASI reassessment in 8 weeks — will initiate biologic referral if inadequate response.',
                                                                                           NOW() - INTERVAL '35 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000009', 'a1000000-0000-0000-0000-000000000015',
                                                                                           'Symptoms of hypothyroidism confirmed — TSH 12.4 mU/L (high), free T4 8.2 pmol/L (low), TPO antibodies strongly positive. Diagnosis: Hashimoto thyroiditis. Started levothyroxine 50mcg daily — to be taken on empty stomach. TFTs recheck in 6 weeks with dose adjustment target TSH 1-2. Explained autoimmune nature of condition and likely lifelong treatment. Palpitations likely related to thyroid; expect resolution with treatment. Patient very relieved to have diagnosis.',
                                                                                           NOW() - INTERVAL '30 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000010', 'a1000000-0000-0000-0000-000000000012',
                                                                                           'Generalised anxiety disorder confirmed — GAD-7 score 17 (severe). Significant occupational impairment and social avoidance. No suicidal ideation. Explored triggers — work pressure and relationship stress identified. Started sertraline 50mg — discussed 2-4 week onset and initial side effects. Urgent CBT referral submitted. Discussed breathing exercises and provided written anxiety management resources. Advised to reduce caffeine. Review in 3 weeks — safety net if acute worsening.',
                                                                                           NOW() - INTERVAL '28 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000011', 'a1000000-0000-0000-0000-000000000004',
                                                                                           'GI symptoms with unintentional 4kg weight loss — red flag requiring investigation. Coeliac serology positive (tTG-IgA elevated). FBC showed mild iron deficiency anaemia. CRP mildly elevated. Omeprazole continued. Referred urgently to gastroenterology for duodenal biopsy to confirm coeliac diagnosis — patient advised to continue eating gluten until biopsy to avoid false negative. Discussed gluten-free diet principle. Colonoscopy referral also submitted to exclude IBD given CRP elevation.',
                                                                                           NOW() - INTERVAL '25 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000012', 'a1000000-0000-0000-0000-000000000008',
                                                                                           'Child with 5 episodes AOM in 12 months — recurrent AOM threshold met for referral. Tympanometry today showed bilateral type B curves — bilateral middle ear effusion. Audiology assessment arranged — mild conductive hearing loss confirmed. ENT referral submitted for grommet assessment. Parent counselled on impact on language and hearing development. Watchful waiting for 3 months while ENT referral processes. Amoxicillin prophylaxis discussed but deferred pending ENT opinion.',
                                                                                           NOW() - INTERVAL '22 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000013', 'a1000000-0000-0000-0000-000000000013',
                                                                                           'Left L5-S1 radiculopathy secondary to suspected disc herniation — MRI lumbar spine ordered urgently given neurological symptoms. Straight leg raise positive at 40 degrees. Motor power intact — no foot drop or cauda equina symptoms. Diclofenac continued with addition of pregabalin 75mg twice daily for neuropathic component. Physiotherapy referral submitted. Strict red flag advice given — advised to attend ED immediately if any bladder or bowel dysfunction develops.',
                                                                                           NOW() - INTERVAL '20 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000014', 'a1000000-0000-0000-0000-000000000020',
                                                                                           'PTSD confirmed — PCL-5 score 52 (significant). 2-year duration following traumatic event. No active suicidal ideation but passive thoughts of hopelessness present. Safety plan agreed and documented. Referred to trauma-focused CBT specialist — priority referral. Discussed EMDR as alternative option. Started sertraline 50mg to address concurrent depressive symptoms and hyperarousal. Psychoeducation provided on PTSD and trauma responses. Weekly check-in calls arranged for first month. Strongly encouraged to share safety plan with a trusted person at home.',
                                                                                           NOW() - INTERVAL '18 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000015', 'a1000000-0000-0000-0000-000000000027',
                                                                                           'Cognitive decline assessment — MoCA score 19/30 (mild cognitive impairment). MMSE 24/30. Family corroborated progressive memory difficulties over 2 years. Bloods unremarkable — B12, folate, TFTs, FBC all normal. MRI brain ordered — look for hippocampal atrophy, white matter changes. Referred to memory clinic for formal neuropsychological testing. Optimised vascular risk management — HbA1c 7.2% (target <7%), ramipril dose reviewed. Discussed diagnosis sensitively with patient and daughter. Advised on driving implications pending further assessment.',
                                                                                           NOW() - INTERVAL '15 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000016', 'a1000000-0000-0000-0000-000000000001',
                                                                                           'Paroxysmal AF confirmed on 7-day patch monitor — 3 episodes captured, longest 4 hours. Echo: mildly dilated left atrium, preserved EF. BP 152/88 — poorly controlled. CHA2DS2-VASc score 3 — anticoagulation indicated. Started apixaban 5mg twice daily after discussing bleeding vs stroke risk. Bisoprolol increased to 5mg for rate control. Referred for cardiology outpatient review and ablation assessment. Lifestyle advice — reduce alcohol, lose weight, treat obstructive sleep apnoea if suspected.',
                                                                                           NOW() - INTERVAL '14 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000017', 'a1000000-0000-0000-0000-000000000002',
                                                                                           'Migraine with aura — 4 attacks in one month, sumatriptan partially effective. Reviewed contraception — patient on combined OCP. Combined OCP contraindicated with migraine with aura due to stroke risk — discussed clearly and agreed to switch to progestogen-only pill. Initiated topiramate 25mg for prevention — titrating to 100mg over 8 weeks. Sumatriptan nasal spray prescribed for superior absorption. Counselled on keeping headache diary and avoiding known triggers. Neurology referral if no improvement at 3 months.',
                                                                                           NOW() - INTERVAL '12 days'),

                                                                                          (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000018', 'a1000000-0000-0000-0000-000000000014',
                                                                                           'New diagnosis type 2 diabetes mellitus confirmed — fasting glucose 14.2 mmol/L, HbA1c 82 mmol/mol. No DKA symptoms — safe to manage in primary care. Metformin 500mg twice daily started, to increase to 1g twice daily at 2 weeks if tolerated. Referred to diabetes education program (DESMOND). Dietary advice provided — low glycaemic index, portion control, limit refined carbohydrates. BP 136/84 — to monitor and treat if persistently elevated. HbA1c recheck in 3 months. Eyes and feet referrals arranged. Discussed long term complications and importance of monitoring.',
                                                                                           NOW() - INTERVAL '10 days');

-- -----------------------------------------------------------------------------
-- 6. REVIEWS (one per completed appointment, realistic ratings and comments)
-- reviews.doctor_id references doctor_profiles.id (b10... UUIDs)
-- -----------------------------------------------------------------------------
INSERT INTO reviews (id, appointment_id, patient_id, doctor_id, rating, comment, created_at) VALUES

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', 5,
                                                                                                  'Dr. Mitchell was incredibly thorough. She took my symptoms seriously straight away and explained everything in terms I could actually understand. I left feeling genuinely cared for and confident in the plan. The follow-up steps were very clear.',
                                                                                                  NOW() - INTERVAL '59 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000002', 'c1000000-0000-0000-0000-000000000002', 'b1000000-0000-0000-0000-000000000005', 5,
                                                                                                  'I was nervous about talking to a psychiatrist for the first time but Dr. Chen made me feel completely at ease within the first few minutes. She listened without judgment, asked exactly the right questions, and made a clear treatment plan. Already feeling more hopeful.',
                                                                                                  NOW() - INTERVAL '54 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000003', 'c1000000-0000-0000-0000-000000000003', 'b1000000-0000-0000-0000-000000000002', 4,
                                                                                                  'Very knowledgeable doctor who clearly understood my migraine problem. He was direct about the medication overuse issue which I needed to hear even though it was uncomfortable. The plan he gave me makes sense. Docking one star only because I wish the appointment was a little longer.',
                                                                                                  NOW() - INTERVAL '49 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000004', 'c1000000-0000-0000-0000-000000000004', 'b1000000-0000-0000-0000-000000000007', 5,
                                                                                                  'Dr. Hassan was the first doctor who has taken my symptoms seriously after years of being dismissed. She used the word endometriosis without me having to bring it up. I felt validated and finally on the right path. Cannot recommend her highly enough.',
                                                                                                  NOW() - INTERVAL '47 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000005', 'c1000000-0000-0000-0000-000000000005', 'b1000000-0000-0000-0000-000000000006', 5,
                                                                                                  'Excellent consultation. Dr. Mendez was calm and reassuring despite what turned out to be a serious knee injury. He explained the likely ACL diagnosis clearly, what the MRI would show, and what the surgical process involves. Very professional and clearly experienced.',
                                                                                                  NOW() - INTERVAL '44 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000006', 'c1000000-0000-0000-0000-000000000006', 'b1000000-0000-0000-0000-000000000003', 4,
                                                                                                  'Dr. Sharma was helpful and identified the trigger I had missed — the new detergent. Practical advice and appropriate medication prescribed. The consultation was efficient. Would appreciate a bit more time to ask questions but overall very satisfied.',
                                                                                                  NOW() - INTERVAL '39 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000007', 'c1000000-0000-0000-0000-000000000007', 'b1000000-0000-0000-0000-000000000011', 5,
                                                                                                  'Dr. Faruk was excellent. He took my palpitations seriously and set up all the right investigations efficiently. He was calm and reassuring which really helped because I was quite frightened. Very clear explanation of what the tests were looking for.',
                                                                                                  NOW() - INTERVAL '37 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000008', 'c1000000-0000-0000-0000-000000000008', 'b1000000-0000-0000-0000-000000000009', 5,
                                                                                                  'Finally a doctor who understands psoriasis properly. Dr. Tanaka assessed my quality of life impact properly and not just how the skin looks. She mentioned biologic therapy as an option which previous doctors had never discussed. Very thorough and compassionate.',
                                                                                                  NOW() - INTERVAL '34 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000009', 'c1000000-0000-0000-0000-000000000009', 'b1000000-0000-0000-0000-000000000015', 5,
                                                                                                  'Dr. Volkov ordered the right tests and had a diagnosis ready at our follow-up. Hypothyroidism confirmed — such a relief to finally know what was wrong. He explained Hashimoto''s clearly and the treatment plan is already working. Exceptional doctor.',
                                                                                                  NOW() - INTERVAL '29 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000010', 'c1000000-0000-0000-0000-000000000010', 'b1000000-0000-0000-0000-000000000012', 5,
                                                                                                  'Dr. Greco was warm, patient, and completely non-judgmental. This was a difficult consultation for me and she made it as easy as it could possibly be. The referral for CBT came through quickly. I feel like I am finally getting the right help.',
                                                                                                  NOW() - INTERVAL '27 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000011', 'b1000000-0000-0000-0000-000000000004', 4,
                                                                                                  'Dr. Okafor was thorough and clearly took my weight loss seriously. The coeliac screen came back positive which explains so much. I am grateful he did not brush off my symptoms. The referral process was smooth. Very competent and caring doctor.',
                                                                                                  NOW() - INTERVAL '24 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000012', 'b1000000-0000-0000-0000-000000000008', 5,
                                                                                                  'Dr. Silva was wonderful with my daughter. She warmed up to him immediately which never happens at the doctor. He explained everything clearly to both of us, arranged the hearing test quickly, and has clearly set us on the right path with the ENT referral.',
                                                                                                  NOW() - INTERVAL '21 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000013', 'b1000000-0000-0000-0000-000000000013', 5,
                                                                                                  'Dr. Kim was superb. He knew immediately from my description and examination what was likely wrong, ordered the right scan, and gave me very clear red flag advice about what to watch for. The additional medication for the nerve pain has already helped.',
                                                                                                  NOW() - INTERVAL '19 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000014', 'c1000000-0000-0000-0000-000000000014', 'b1000000-0000-0000-0000-000000000020', 5,
                                                                                                  'I have never spoken to a doctor about what happened to me before. Dr. Diallo created a space where I felt completely safe to do that. She was compassionate and professional throughout and the safety plan we made together gave me real comfort. Truly exceptional care.',
                                                                                                  NOW() - INTERVAL '17 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000015', 'c1000000-0000-0000-0000-000000000015', 'b1000000-0000-0000-0000-000000000027', 4,
                                                                                                  'Dr. Wei was thorough and sensitive when discussing the memory assessment results with us. He explained the findings clearly without being alarmist. My mother felt respected throughout. The memory clinic referral was submitted promptly. A very reassuring doctor to see.',
                                                                                                  NOW() - INTERVAL '14 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000016', 'c1000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000022', 5,
                                                                                                  'Dr. Fischer identified my irregular heartbeat pattern from the monitor results and explained atrial fibrillation in a way that made complete sense. She was very clear about why anticoagulation was important and made sure I understood before I agreed to start it.',
                                                                                                  NOW() - INTERVAL '13 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000017', 'c1000000-0000-0000-0000-000000000003', 'b1000000-0000-0000-0000-000000000021', 4,
                                                                                                  'Dr. Novak caught something important — the interaction between my migraines with aura and the contraceptive pill I was taking. No other doctor had ever mentioned this risk. I''m glad I came. The switch in contraception and the new preventive treatment plan are very sensible.',
                                                                                                  NOW() - INTERVAL '11 days'),

                                                                                                 (gen_random_uuid(), 'd1000000-0000-0000-0000-000000000018', 'c1000000-0000-0000-0000-000000000005', 'b1000000-0000-0000-0000-000000000014', 5,
                                                                                                  'Dr. Malik was calm and thorough when delivering what was difficult news — a new diabetes diagnosis. She explained everything clearly, was not alarmist, and gave me a very clear action plan. I left feeling informed and in control rather than scared. Excellent doctor.',
                                                                                                  NOW() - INTERVAL '9 days');

-- -----------------------------------------------------------------------------
-- 7. UPDATE doctor average_rating and review_count
-- -----------------------------------------------------------------------------
UPDATE doctor_profiles dp
SET
    average_rating = sub.avg_rating,
    review_count   = sub.cnt
    FROM (
    SELECT doctor_id, ROUND(AVG(rating)::numeric, 2) AS avg_rating, COUNT(*) AS cnt
    FROM reviews
    GROUP BY doctor_id
) sub
WHERE dp.id = sub.doctor_id;

-- -----------------------------------------------------------------------------
-- 8. FORUM POSTS (20 posts across all 6 categories, mix of patients and doctors)
-- -----------------------------------------------------------------------------
INSERT INTO forum_posts (id, author_id, title, content, category, likes_count, created_at) VALUES

                                                                                               ('e1000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000001',
                                                                                                'Finally got a diagnosis after 3 years of chest symptoms',
                                                                                                'I just wanted to share my experience because I know how frustrating it can be to feel like something is wrong but not get answers. I had been experiencing chest tightness and breathlessness on exertion for nearly three years. Multiple visits to my GP, always told it was anxiety or that I was deconditioned. Finally saw a cardiologist through MedConnect who ordered a stress echocardiogram and found a significant issue with my coronary arteries that had been missed. I am now on appropriate treatment and feeling so much better. If you have been dismissed and feel something is genuinely wrong, please keep advocating for yourself. You know your body.',
                                                                                                'GENERAL_HEALTH', 24, NOW() - INTERVAL '55 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000005',
                                                                                                'Understanding anxiety: what is actually happening in your brain',
                                                                                                'As a psychiatrist I see a lot of patients who feel ashamed of their anxiety, as if it is a weakness or a character flaw. I want to explain what is actually happening biologically because I think it helps to know your brain is not broken — it is overprotective. Anxiety is driven by the amygdala, your brain''s alarm system, which has learned to fire in response to perceived threats even when no real danger exists. This is a survival mechanism that has gone into overdrive. The good news is that the brain is neuroplastic — it can learn new responses. This is exactly what cognitive behavioural therapy targets. If you are struggling with anxiety, please do not suffer in silence. Effective treatments exist and you deserve to access them.',
                                                                                                'MENTAL_HEALTH', 87, NOW() - INTERVAL '50 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000003', 'c1000000-0000-0000-0000-000000000003',
                                                                                                'Does anyone else get migraines triggered by certain foods?',
                                                                                                'I have had migraines for about 10 years but only recently started keeping a food diary and I am shocked by the patterns I am finding. Red wine is an obvious one but I have also found that aged cheese, processed meats, and even some dark chocolates seem to be triggers for me within about 12 to 24 hours of eating them. My neurologist mentioned that these foods contain tyramine which can affect serotonin levels in a way that may trigger migraines in susceptible people. Has anyone else identified food triggers? I am curious whether MSG is a genuine trigger or whether that is a myth. Would love to hear what others have found.',
                                                                                                'NUTRITION', 31, NOW() - INTERVAL '47 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000006',
                                                                                                'Returning to sport after ACL reconstruction: what to expect',
                                                                                                'I see many patients who are anxious about their recovery timeline after ACL reconstruction and I want to provide some realistic expectations. The surgery itself typically takes 60 to 90 minutes and most patients go home the same day. The first 6 weeks focus on reducing swelling and regaining range of motion. Running usually begins around 12 weeks if quadriceps strength is progressing well. Return to sport is typically 9 to 12 months — and I cannot stress enough that this timeline should be based on functional criteria, not just the calendar. Psychological readiness is also a real factor; many athletes struggle with fear of re-injury. Do not rush it. A second ACL tear within 2 years is significantly more likely if you return before truly ready.',
                                                                                                'FITNESS', 62, NOW() - INTERVAL '44 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000005', 'c1000000-0000-0000-0000-000000000006',
                                                                                                'Living with eczema as an adult — what actually helps',
                                                                                                'I have had atopic eczema since childhood but it got significantly worse in my late twenties. I wanted to share what has genuinely made a difference for me after years of trial and error. First, daily moisturising with a thick emollient (not a light lotion) is non-negotiable — I do it twice a day even when my skin looks fine. Second, switching to fragrance-free everything: detergent, soap, shampoo. Third, wearing cotton against the skin and avoiding wool or synthetic fabrics. The biggest game changer for me was starting dupilumab injections after my dermatologist referred me. Within 3 months my skin was clearer than it had been in 15 years. If you are struggling with moderate to severe eczema, ask about biologics — they are not just for the most extreme cases.',
                                                                                                'CHRONIC_CONDITIONS', 45, NOW() - INTERVAL '38 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000006', 'a1000000-0000-0000-0000-000000000003',
                                                                                                'Sunscreen myths and facts from a dermatologist',
                                                                                                'There is so much misinformation about sunscreen circulating online and I want to address the most common myths I encounter. Myth one: you do not need sunscreen on cloudy days. False — up to 80% of UV radiation penetrates cloud cover. Myth two: darker skin tones do not need sunscreen. False — while melanin offers some natural protection, skin cancer and photoageing affect all skin tones. Myth three: SPF 50 is twice as protective as SPF 25. False — SPF 25 blocks 96% of UVB, SPF 50 blocks 98%. The difference is small but SPF 30 to 50 is still the recommended minimum. Myth four: sunscreen causes vitamin D deficiency. The evidence does not support this in practice. Please wear your SPF every day.',
                                                                                                'GENERAL_HEALTH', 103, NOW() - INTERVAL '35 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000007', 'c1000000-0000-0000-0000-000000000009',
                                                                                                'Newly diagnosed with Hashimoto''s — questions and anxiety',
                                                                                                'I was diagnosed with Hashimoto''s thyroiditis last month after months of feeling exhausted, cold, and losing hair. My doctor started me on levothyroxine and said it would take several weeks to feel a difference. I am finding the wait really difficult. I have been reading online and going down rabbit holes about Hashimoto''s and feel quite overwhelmed. Has anyone else been through this? How long did it take before the levothyroxine started working for you? Also I keep reading about T3 and T4 combination therapy — is that something worth asking my doctor about? Any advice from people who have been managing this condition for a while would be really appreciated.',
                                                                                                'CHRONIC_CONDITIONS', 38, NOW() - INTERVAL '28 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000008', 'a1000000-0000-0000-0000-000000000015',
                                                                                                'Atrial fibrillation: separating fact from fear',
                                                                                                'Atrial fibrillation is the most common heart rhythm disorder I treat and also one of the most frightening diagnoses for patients to receive. I want to demystify it. AF means the upper chambers of your heart are beating chaotically instead of in a coordinated rhythm. It is not immediately life threatening in most cases. The main risks over time are stroke (because blood can pool and clot in the fibrillating atrium) and heart failure from persistently fast rates. Both of these risks are very manageable with the right treatment. Anticoagulation for stroke prevention is highly effective and modern drugs like apixaban and rivaroxaban are much more convenient than warfarin. AF does not mean your life is over — millions of people live full, active lives with it.',
                                                                                                'CHRONIC_CONDITIONS', 74, NOW() - INTERVAL '25 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000009', 'c1000000-0000-0000-0000-000000000011',
                                                                                                'Anti-inflammatory foods that have helped my gut symptoms',
                                                                                                'After being diagnosed with suspected coeliac disease and going through investigations, I started researching what foods support gut health and reduce inflammation. A few things that have genuinely made a noticeable difference to my symptoms while I was waiting for my biopsy results: cutting out all gluten obviously, but also reducing processed foods and added sugar which seem to aggravate things. Adding more oily fish (salmon, sardines, mackerel) for omega-3s, fermented foods like kefir and sauerkraut for gut bacteria, and lots of colourful vegetables especially leafy greens. I am not a doctor so I cannot give medical advice, but talking to a registered dietitian who specialises in GI conditions was one of the best things I did alongside my medical care.',
                                                                                                'NUTRITION', 29, NOW() - INTERVAL '22 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000010', 'a1000000-0000-0000-0000-000000000012',
                                                                                                'Why trauma responses are not a sign of weakness',
                                                                                                'In my work as a trauma psychiatrist I want to address something my patients often say: that they feel weak for struggling after a traumatic experience. Trauma responses — including flashbacks, nightmares, hypervigilance, and avoidance — are not signs of weakness or character flaws. They are the result of your nervous system doing exactly what it evolved to do: trying to protect you from something it has identified as dangerous. The problem is that these protective responses can become stuck and fire even when you are no longer in danger. Healing from trauma is not about being strong enough to push through it — it is about working with a trained therapist to help your nervous system learn that the danger has passed. If you are struggling, please reach out for support.',
                                                                                                'MENTAL_HEALTH', 91, NOW() - INTERVAL '20 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000011', 'c1000000-0000-0000-0000-000000000004',
                                                                                                'Managing endometriosis day to day — tips from someone who has been at it for years',
                                                                                                'I was finally diagnosed with endometriosis after 6 years of being told my periods were just painful. Since my laparoscopic surgery and starting continuous combined hormonal therapy, my quality of life has improved enormously. Some things that help me day to day: a heating pad for pelvic pain is genuinely effective — there is evidence it works as well as ibuprofen for muscle cramping. Gentle yoga and swimming help me more than high-impact exercise on bad days. Tracking my symptoms in a period app means I can anticipate bad days and plan around them. Dietary changes (reducing red meat and refined carbs, increasing omega-3) have helped some of my bloating. Most importantly: finding a gynaecologist who specialises in endometriosis made all the difference.',
                                                                                                'CHRONIC_CONDITIONS', 56, NOW() - INTERVAL '18 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000012', 'a1000000-0000-0000-0000-000000000008',
                                                                                                'Fever in children: when to worry and when to wait',
                                                                                                'As a paediatrician I get this question constantly from worried parents and I want to give clear, practical guidance. A fever is not an illness — it is a sign the immune system is working. In children over 3 months, a temperature up to 39°C with no other worrying features can generally be managed at home with paracetamol or ibuprofen, good hydration, and monitoring. You should seek urgent medical attention for: any fever in a baby under 3 months, a temperature over 40°C, fever lasting more than 5 days, a child who is unusually drowsy or difficult to rouse, a non-blanching rash, difficulty breathing, or a parent or carer who simply has a gut feeling something is seriously wrong. That last point matters — parents know their children.',
                                                                                                'GENERAL_HEALTH', 118, NOW() - INTERVAL '16 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000013', 'c1000000-0000-0000-0000-000000000013',
                                                                                                'Low back pain and exercise — what I learned the hard way',
                                                                                                'I herniated a disc lifting boxes at work about a month ago and the pain has been some of the worst I have experienced. I wanted to share what I learned because I made mistakes at the start that made things worse. The first thing I did wrong was rest completely. My physiotherapist told me that bed rest beyond 48 hours actually slows recovery for most disc injuries — gentle movement is important even when it is uncomfortable. The second mistake was waiting too long to start physiotherapy. The third was continuing to sit for long periods at my desk which loaded my spine terribly. What helped: regular short walks, specific physiotherapy exercises for my disc level, an adjustable standing desk, and a lumbar support cushion. Progress has been slow but steady.',
                                                                                                'FITNESS', 33, NOW() - INTERVAL '14 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000014', 'a1000000-0000-0000-0000-000000000025',
                                                                                                'Talking to your doctor about addiction: removing the shame barrier',
                                                                                                'Addiction is a medical condition — a chronic brain disorder — not a moral failing. Yet shame is one of the biggest barriers stopping people from seeking the help they need and deserve. As an addiction psychiatrist, I want to be direct: your doctor has heard it all before, is not there to judge you, and cannot help you effectively if you are not honest with them. The best outcomes in addiction treatment happen when patients and clinicians work as partners. If you have tried to disclose a problem with alcohol or substances and felt judged or dismissed, please try again with a different doctor. A non-judgmental, trauma-informed approach to addiction is what you deserve. Effective treatments for alcohol use disorder, opioid dependence, and other substance issues exist — please reach out.',
                                                                                                'MENTAL_HEALTH', 67, NOW() - INTERVAL '12 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000015', 'c1000000-0000-0000-0000-000000000007',
                                                                                                'Palpitations that turned out to be nothing serious — my experience',
                                                                                                'For about two months I had episodes of my heart racing and fluttering, sometimes with chest discomfort. I was absolutely convinced something was terribly wrong. I was seen by a cardiologist who took it very seriously, did an ECG, fitted a Holter monitor, and ordered an echocardiogram. The results showed benign ectopic beats — basically harmless extra heartbeats that feel dramatic but are not dangerous in the absence of structural heart disease. Knowing there was no structural problem was enormously reassuring. The cardiologist advised reducing caffeine, improving sleep, and managing stress. Most of the palpitations have reduced significantly since I cut out coffee. Sharing this in case someone else is going through the same frightening experience.',
                                                                                                'GENERAL_HEALTH', 41, NOW() - INTERVAL '10 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000016', 'a1000000-0000-0000-0000-000000000009',
                                                                                                'Psoriasis and mental health: the connection nobody talks about enough',
                                                                                                'In my dermatology practice I have become increasingly aware that treating the skin alone is not enough for psoriasis patients. Research consistently shows that people with psoriasis have significantly higher rates of depression and anxiety than the general population — and this relationship goes both ways. Psychological stress is one of the most powerful psoriasis triggers, and active psoriasis causes significant psychological distress, especially when it affects visible areas. The stigma of visible skin disease is real and should not be minimised. I now routinely screen my psoriasis patients for depression and refer when appropriate. If you are living with psoriasis and struggling emotionally, please mention it to your dermatologist. It is very much part of the condition.',
                                                                                                'MENTAL_HEALTH', 52, NOW() - INTERVAL '8 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000017', 'c1000000-0000-0000-0000-000000000002',
                                                                                                'My experience with CBT for depression — it actually works',
                                                                                                'I was sceptical about CBT when my psychiatrist first suggested it alongside medication. I thought talking about my thoughts could not possibly change how I felt. I was wrong. After 16 sessions with a CBT therapist I learned to identify the cognitive distortions that were driving my low mood — catastrophising, black and white thinking, mind-reading. More importantly, I learned practical techniques to challenge them in the moment. Combined with sertraline, the improvement in my mood over 6 months was significant. I still have difficult days but I now have tools to work with them rather than being swept away. If you have been offered CBT and are hesitant, I would really encourage you to try it. The evidence base is solid.',
                                                                                                'MENTAL_HEALTH', 44, NOW() - INTERVAL '6 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000018', 'a1000000-0000-0000-0000-000000000004',
                                                                                                'Why you should not ignore pre-diabetes',
                                                                                                'Pre-diabetes — a fasting glucose or HbA1c just above normal but not yet diagnostic for diabetes — is reversible in many people with lifestyle intervention. Yet in my primary care practice I see patients who were told they had pre-diabetes and received no follow-up guidance beyond "watch what you eat." That is not enough. The evidence is clear that intensive lifestyle intervention (5-7% weight loss, 150 minutes moderate exercise per week, Mediterranean-style diet) can reduce progression to type 2 diabetes by 58%. That is better than metformin alone. If you have been told you have pre-diabetes or borderline blood sugar, please take it seriously and ask your doctor to refer you to a structured prevention programme. The window to reverse course is real.',
                                                                                                'NUTRITION', 79, NOW() - INTERVAL '4 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000019', 'c1000000-0000-0000-0000-000000000005',
                                                                                                'Newly diagnosed type 2 diabetes — sharing what helped me in the first weeks',
                                                                                                'I was diagnosed with type 2 diabetes a couple of weeks ago and the first few days were overwhelming. I wanted to share what helped me get through the initial shock and start making progress. First, finding a diabetes education programme was invaluable — being in a group with other newly diagnosed people and learning from a diabetes nurse and dietitian together was so much more helpful than reading information sheets alone. Second, getting a blood glucose monitor and actually seeing how different foods affect my levels in real time was a revelation. White bread spiked my glucose far more than I expected. Third, daily walking — even just 20 minutes after dinner — has made a measurable difference to my morning glucose readings. This is manageable. It gets easier.',
                                                                                                'CHRONIC_CONDITIONS', 36, NOW() - INTERVAL '2 days'),

                                                                                               ('e1000000-0000-0000-0000-000000000020', 'a1000000-0000-0000-0000-000000000027',
                                                                                                'Early signs of cognitive decline: what families should know',
                                                                                                'As a neurologist specialising in dementia I am frequently asked by families what signs they should look for and when to seek assessment. Normal ageing includes occasional forgetfulness — misplacing keys, forgetting a name temporarily, taking longer to learn new technology. These are not early dementia. Signs that warrant medical assessment include: repeatedly asking the same questions in a short time frame, getting lost in familiar places, significant personality or behaviour changes, difficulty managing finances or medication that was previously routine, and language difficulties such as struggling to find common words. If you have concerns about a family member, a GP assessment with cognitive screening tools is the first step. Early assessment matters because many reversible causes (thyroid, B12, depression) can mimic dementia, and earlier diagnosis means earlier support.',
                                                                                                'GENERAL_HEALTH', 88, NOW() - INTERVAL '1 day');

-- -----------------------------------------------------------------------------
-- 9. FORUM COMMENTS (realistic threaded discussion on several posts)
-- -----------------------------------------------------------------------------
INSERT INTO forum_comments (id, post_id, author_id, parent_comment_id, content, likes_count, created_at) VALUES

-- Comments on post 1 (Finally got a diagnosis)
('f1000000-0000-0000-0000-000000000001', 'e1000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000003', NULL,
 'This really resonates with me. I spent two years being told my headaches were stress-related before a neurologist finally took proper history and identified a pattern that needed investigation. Persistence absolutely pays off.',
 8, NOW() - INTERVAL '54 days'),
('f1000000-0000-0000-0000-000000000002', 'e1000000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001', NULL,
 'Thank you for sharing this. As a cardiologist I want to echo your point — exertional symptoms in particular should always be properly evaluated. If you are ever told your breathlessness on exercise is just deconditioning without any investigation, it is entirely reasonable to ask for more.',
 15, NOW() - INTERVAL '53 days'),
('f1000000-0000-0000-0000-000000000003', 'e1000000-0000-0000-0000-000000000001', 'c1000000-0000-0000-0000-000000000007', 'f1000000-0000-0000-0000-000000000002',
 'Dr. Mitchell is this the sort of thing that could be caught with a standard blood pressure check or does it really need imaging to find?',
 3, NOW() - INTERVAL '52 days'),
('f1000000-0000-0000-0000-000000000004', 'e1000000-0000-0000-0000-000000000001', 'a1000000-0000-0000-0000-000000000001', 'f1000000-0000-0000-0000-000000000003',
 'Great question. A blood pressure check is important but often not enough on its own. An ECG and an exercise stress test or stress echocardiogram are the key investigations for exertional symptoms. Please do not rely on a BP reading alone if you have symptoms on exertion.',
 11, NOW() - INTERVAL '51 days'),

-- Comments on post 2 (Understanding anxiety)
('f1000000-0000-0000-0000-000000000005', 'e1000000-0000-0000-0000-000000000002', 'c1000000-0000-0000-0000-000000000002', NULL,
 'This is exactly what I needed to read today. I have been feeling so ashamed of my anxiety and like I should just be able to think my way out of it. Knowing it is a brain mechanism and not a personal failing genuinely helps.',
 22, NOW() - INTERVAL '49 days'),
('f1000000-0000-0000-0000-000000000006', 'e1000000-0000-0000-0000-000000000002', 'c1000000-0000-0000-0000-000000000010', NULL,
 'I struggled with this for years before finally trying CBT. The change was remarkable. I wish someone had explained the neuroscience to me earlier — it would have helped me take the treatment more seriously rather than feeling like I was being fobbed off with talking therapy.',
 17, NOW() - INTERVAL '48 days'),
('f1000000-0000-0000-0000-000000000007', 'e1000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000005', 'f1000000-0000-0000-0000-000000000006',
 'Really glad CBT helped. The evidence for it in anxiety disorders is very strong. For people who cannot access it quickly, there are also NICE-recommended self-guided CBT workbooks and apps that use the same principles. Ask your GP about what is available locally.',
 14, NOW() - INTERVAL '47 days'),

-- Comments on post 5 (Living with eczema)
('f1000000-0000-0000-0000-000000000008', 'e1000000-0000-0000-0000-000000000005', 'c1000000-0000-0000-0000-000000000008', NULL,
 'The fragrance-free everything point is so important and so underestimated. I had no idea my fabric conditioner was triggering my flares until I cut it out. Such a simple change that made a huge difference.',
 9, NOW() - INTERVAL '37 days'),
('f1000000-0000-0000-0000-000000000009', 'e1000000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000003', NULL,
 'Excellent practical advice. I want to add one more thing from a dermatology perspective: shower temperature matters. Hot showers strip the skin barrier significantly. Lukewarm water and patting dry rather than rubbing makes a real difference for eczema-prone skin.',
 18, NOW() - INTERVAL '36 days'),
('f1000000-0000-0000-0000-000000000010', 'e1000000-0000-0000-0000-000000000005', 'c1000000-0000-0000-0000-000000000006', 'f1000000-0000-0000-0000-000000000009',
 'Dr. Sharma that is a really good tip about shower temperature. I had not connected my longer hot showers in winter with my eczema being worse in winter. Going to try this.',
 6, NOW() - INTERVAL '35 days'),

-- Comments on post 7 (Hashimoto's questions)
('f1000000-0000-0000-0000-000000000011', 'e1000000-0000-0000-0000-000000000007', 'c1000000-0000-0000-0000-000000000015', NULL,
 'I was diagnosed 4 years ago. It took about 6 to 8 weeks on levothyroxine before I really noticed a difference, and another 6 months to feel completely optimised once the dose was adjusted. Be patient with the process — the improvement is real but slow.',
 19, NOW() - INTERVAL '27 days'),
('f1000000-0000-0000-0000-000000000012', 'e1000000-0000-0000-0000-000000000007', 'a1000000-0000-0000-0000-000000000015', NULL,
 'On the T3/T4 combination question — the evidence for combination therapy over levothyroxine alone is limited and it is not recommended as first-line. Most people do very well on levothyroxine alone once their dose is optimised. Give it time before exploring alternatives.',
 24, NOW() - INTERVAL '26 days'),
('f1000000-0000-0000-0000-000000000013', 'e1000000-0000-0000-0000-000000000007', 'c1000000-0000-0000-0000-000000000009', 'f1000000-0000-0000-0000-000000000011',
 'I can confirm the 6 to 8 week timeline. I wanted to feel better immediately and got discouraged but around week 7 I suddenly noticed I had more energy. Keep going and make sure your 6 week TFT recheck is booked.',
 12, NOW() - INTERVAL '25 days'),

-- Comments on post 12 (Fever in children)
('f1000000-0000-0000-0000-000000000014', 'e1000000-0000-0000-0000-000000000012', 'c1000000-0000-0000-0000-000000000012', NULL,
 'This is incredibly helpful to have laid out clearly. The non-blanching rash point is something every parent should know about — that is the meningitis warning sign. I have it saved as a reference.',
 31, NOW() - INTERVAL '15 days'),
('f1000000-0000-0000-0000-000000000015', 'e1000000-0000-0000-0000-000000000012', 'a1000000-0000-0000-0000-000000000008', 'f1000000-0000-0000-0000-000000000014',
 'Exactly right. The glass test for a non-blanching rash is easy to do at home — press a clear glass firmly against the rash. If it does not fade under pressure, seek emergency care immediately. It is one of the most important things parents can know.',
 27, NOW() - INTERVAL '14 days'),

-- Comments on post 20 (Early signs of cognitive decline)
('f1000000-0000-0000-0000-000000000016', 'e1000000-0000-0000-0000-000000000020', 'c1000000-0000-0000-0000-000000000015', NULL,
 'Thank you for this clear explanation of what is normal versus concerning. We noticed my mother repeating the same questions several times in one afternoon and were not sure if we were overreacting. This confirms we should book a GP appointment.',
 16, NOW() - INTERVAL '20 hours'),
('f1000000-0000-0000-0000-000000000017', 'e1000000-0000-0000-0000-000000000020', 'a1000000-0000-0000-0000-000000000027', 'f1000000-0000-0000-0000-000000000016',
 'You are not overreacting — repeating questions in a short timeframe is one of the key signs to take seriously. Please do book that appointment. As I mentioned in the post, there are many reversible causes to rule out first. Early assessment is always the right call.',
 21, NOW() - INTERVAL '18 hours'),
('f1000000-0000-0000-0000-000000000018', 'e1000000-0000-0000-0000-000000000020', 'c1000000-0000-0000-0000-000000000011', NULL,
 'My father was diagnosed last year. I wish I had known to look for the financial management changes earlier — he had been struggling with his bills for months and we just put it down to him being disorganised. Raising awareness like this is so valuable.',
 13, NOW() - INTERVAL '16 hours');

